'use client'

import { useState } from 'react'

function randomChar(pool: string) {
  return pool[Math.floor(Math.random() * pool.length)]
}

export default function PasswordGenerator() {
  const [length, setLength] = useState(12)
  const [includeSymbols, setIncludeSymbols] = useState(true)
  const [includeNumbers, setIncludeNumbers] = useState(true)
  const [password, setPassword] = useState('')

  function generate() {
    const lower = 'abcdefghijklmnopqrstuvwxyz'
    const upper = lower.toUpperCase()
    const numbers = '0123456789'
    const symbols = '!@#$%^&*()_+-=[]{}|;:,.<>?'
    let pool = lower + upper
    if (includeNumbers) pool += numbers
    if (includeSymbols) pool += symbols
    let pass = ''
    for (let i = 0; i < length; i++) pass += randomChar(pool)
    setPassword(pass)
  }

  return (
    <main className="container mx-auto p-4">
      <h1 className="text-2xl font-bold">Password Generator</h1>
      <div className="mt-4 max-w-md">
        <label className="block">Length
          <input type="range" min={6} max={32} value={length} onChange={e => setLength(parseInt(e.target.value))} />
          <div>{length}</div>
        </label>

        <label className="flex items-center gap-2 mt-2"><input type="checkbox" checked={includeNumbers} onChange={e => setIncludeNumbers(e.target.checked)} />Include Numbers</label>
        <label className="flex items-center gap-2 mt-2"><input type="checkbox" checked={includeSymbols} onChange={e => setIncludeSymbols(e.target.checked)} />Include Symbols</label>

        <div className="flex gap-2 mt-3">
          <button onClick={generate} className="px-4 py-2 bg-blue-600 text-white rounded">Generate</button>
          <button onClick={() => navigator.clipboard.writeText(password)} className="px-4 py-2 border rounded">Copy</button>
        </div>

        {password && <div className="mt-4 p-3 bg-slate-50 dark:bg-slate-800 rounded font-mono">{password}</div>}
      </div>
    </main>
  )
}
